INSERT INTO status_messages (content, type) VALUES ('Tip: Use /review/grade 5 to grade a card as "Easy" (SM-2: Ease increases).', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /review session stops if you get a card wrong to help you focus.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use igt --handbook --days=0 to generate a handbook of all-time errors.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can search your input history with ctrl+r in some terminals.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT saves raw LLM responses to igt_db_error.log if a parse error occurs.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The IGT_REVIEW_PATH env var determines where review logs are saved.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /stats --category=Grammar to focus on structural mistakes.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /vocab command also saves the sentence context where the word was used.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT supports local Ollama models for 100% private grammar checks.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /review --limit=5 to do a quick 5-card session.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The "Stability" of a card represents how long it will stay in your memory.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: A "Graduated" card has an interval long enough to be considered "learned".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /stats --top=5 to see your most frequent "linguistic fingerprints".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The migrations/ folder contains the evolution of the IGT database schema.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can run npm test to verify the logic of the SRS and LLM providers.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT uses ANSI escape codes for a colorful and interactive CLI experience.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /help <command> for detailed information on a specific action.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /diagnoses severity levels are: Minor, Moderate, and Major.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Major errors significantly impact the clarity or meaning of your sentence.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Minor errors are usually small slips in mechanics or style.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /refine to see how a professional editor would rewrite your text.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT''s "Mastery" score is a weighted average of your recent performance.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can import legacy Markdown review logs using tools/import-review-to-db.mjs.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /practice exercises target your specific "bottlenecks".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /gemini-pro for higher-quality handbook generation.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT handles rate limits for major LLM providers automatically.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can manage multiple API keys in your .env file for redundancy.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /review/reset to move a specific card back to the "New" state.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The status bar''s message is chosen randomly using a weighted algorithm.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: "Logical Inconsistency" errors check if your sentence makes sense internally.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: "Tone & Register" suggests if your language is too formal or casual.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /stats --export=csv to get your data for external analysis.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT was designed to make English learning interactive and low-friction.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Every mistake is a learning opportunity — keep typing!', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "shampoo" comes from a Hindi word meaning "to massage".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Go" is the shortest complete sentence in the English language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Subbookkeeper" is the only word with four consecutive double letters.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "nerd" was first coined by Dr. Seuss in 1950.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Ewe" and "you" are pronounced exactly the same but have no letters in common.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "clue" originally meant a ball of thread.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Nouns) "Data" was originally the plural of "datum," but is now often used as a singular mass noun.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Prepositions) "Into" implies movement toward the inside; "in" implies position.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Subject-Verb) "The number of..." takes a singular verb; "A number of..." takes a plural verb.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Articles) Names of most countries do not take an article, but "The United States" and "The Netherlands" do.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The dot on top of "i" and "j" is officially called a "tittle".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Facetious" contains all the vowels in alphabetical order.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "trivia" comes from the Latin for "three roads".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Spelling) "Accommodate" has two "c"s and two "m"s.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Punctuation) The "slash" (/) is also known as a virgule.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "lucid" comes from the Latin word for "light".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Dreamt" is the only English word ending in "mt".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Verbs) "Will" and "shall" used to have different rules for different persons, but they are now mostly interchangeable.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Nouns) "Physics" and "Mathematics" are singular despite ending in "s".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: English has the largest vocabulary of any language in the world.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: About 4,000 words are added to the dictionary every year.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Stewardesses" is the longest word that can be typed with only the left hand.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Lol" was added to the Oxford English Dictionary in 2011.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Adjectives) "Oldest" is used for age; "eldest" is specifically for family members.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Pronouns) "Mine" and "Yours" are possessive pronouns; they do not use apostrophes.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Listen" is an anagram of "silent".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "alphabet" is derived from the first two Greek letters.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Word Order) Adverbs of frequency (like "always") usually go before the main verb.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Tense) The past perfect tense ("had done") describes an action completed before another past action.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Conjunctions) "Unless" means "if not".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "synonym" does not have a synonym (mostly).', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Clarity) Avoid "empty" subjects like "It is..." to make your writing more direct.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Rhythms" is the longest word without a vowel (excluding "y").', 'grammar_fact');
INSERT INTO status_messages (content, type, author) VALUES ('"Mistakes are the portals of discovery."', 'quote', 'James Joyce');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is a process of free creation; its laws and principles are fixed, but the manner in which the principles of generation are used is free and infinitely varied."', 'quote', 'Noam Chomsky');
INSERT INTO status_messages (content, type, author) VALUES ('"The word ''listen'' contains the same letters as the word ''silent''."', 'quote', 'Alfred Brendel');
INSERT INTO status_messages (content, type, author) VALUES ('"A language is a system of arbitrary vocal symbols by means of which a social group cooperates."', 'quote', 'Bernard Bloch');
INSERT INTO status_messages (content, type, author) VALUES ('"The structure of a language determines the way in which speakers of that language perceive the world."', 'quote', 'Benjamin Lee Whorf');
INSERT INTO status_messages (content, type, author) VALUES ('"Slang is a language that rolls up its sleeves, spits on its hands and goes to work."', 'quote', 'Carl Sandburg');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is a city to the building of which every human being brought a stone."', 'quote', 'Ralph Waldo Emerson');
INSERT INTO status_messages (content, type, author) VALUES ('"Words are but symbols for the relations of things to one another and to us; nowhere do they touch upon absolute truth."', 'quote', 'Friedrich Nietzsche');
INSERT INTO status_messages (content, type, author) VALUES ('"Proper words in proper places, make the true definition of a style."', 'quote', 'Jonathan Swift');
INSERT INTO status_messages (content, type, author) VALUES ('"All language is but a poor translation."', 'quote', 'Franz Kafka');
INSERT INTO status_messages (content, type, author) VALUES ('"The difference between the right word and the almost right word is the difference between lightning and a lightning bug."', 'quote', 'Mark Twain');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the mother of thought, not its handmaid."', 'quote', 'Karl Kraus');
INSERT INTO status_messages (content, type, author) VALUES ('"Words are the voice of the heart."', 'quote', 'Confucius');
INSERT INTO status_messages (content, type, author) VALUES ('"Kind words can be short and easy to speak, but their echoes are truly endless."', 'quote', 'Mother Teresa');
INSERT INTO status_messages (content, type, author) VALUES ('"The Pen is mightier than the Sword."', 'quote', 'Edward Bulwer-Lytton');
INSERT INTO status_messages (content, type, author) VALUES ('"Good words are worth much, and cost little."', 'quote', 'George Herbert');
INSERT INTO status_messages (content, type, author) VALUES ('"The word is half his that speaks, and half his that hears it."', 'quote', 'Michel de Montaigne');
INSERT INTO status_messages (content, type, author) VALUES ('"A word is not a crystal, transparent and unchanged; it is the skin of a living thought."', 'quote', 'Oliver Wendell Holmes Jr.');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the invention of people who want to catch and hold the world."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"Without words, without writing and without books there would be no history, there could be no concept of humanity."', 'quote', 'Hermann Hesse');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is a tool of the mind."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"A nation is a group of people who share the same language and the same history."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"The first step toward wisdom is calling things by their right names."', 'quote', 'Chinese Proverb');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the dress of thought."', 'quote', 'Samuel Johnson');
INSERT INTO status_messages (content, type, author) VALUES ('"Words are the pegs to hang ideas on."', 'quote', 'Henry Ward Beecher');
INSERT INTO status_messages (content, type, author) VALUES ('"One forgetful word can seal a fate."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"The turn of a sentence can change a mood."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"Words have the power to both destroy and heal."', 'quote', 'Buddha');
INSERT INTO status_messages (content, type, author) VALUES ('"In the beginning was the Word."', 'quote', 'Bible');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the house of being."', 'quote', 'Martin Heidegger');
INSERT INTO status_messages (content, type, author) VALUES ('"The limits of my language are the limits of my mind."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"Talk is cheap, but words are precious."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"Silence is the language of God, all else is poor translation."', 'quote', 'Rumi');
